 using System.ComponentModel;
 using System.Text.Json;
 using Microsoft.Extensions.Logging;
 using ModelContextProtocol.Server;

 /// <summary>
 /// MCP tools that wrap a REST API using HttpClient.
 /// Uses constructor injection — the SDK resolves DI services automatically
 /// and they do not appear in the tool schema exposed to the LLM.
 /// </summary>
 [McpServerToolType]
 public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
 {
     private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

     [McpServerTool, Description("Retrieve a single item from the API by its numeric ID.")]
     public async Task<string> GetItem(
         [Description("The numeric ID of the item to retrieve")] int id,
         CancellationToken cancellationToken = default)
     {
         logger.LogInformation("Fetching item {Id}", id);
         var response = await httpClient.GetAsync($"/posts/{id}", cancellationToken);
         response.EnsureSuccessStatusCode();
         var json = await response.Content.ReadAsStringAsync(cancellationToken);
         return json;
     }

     [McpServerTool, Description("List items from the API, optionally filtered by user ID.")]
     public async Task<string> ListItems(
         [Description("Filter results to this user ID (omit for all users)")] int? userId = null,
         CancellationToken cancellationToken = default)
     {
         var url = userId.HasValue ? $"/posts?userId={userId}" : "/posts";
         logger.LogInformation("Listing items from {Url}", url);
         var response = await httpClient.GetAsync(url, cancellationToken);
         response.EnsureSuccessStatusCode();
         var json = await response.Content.ReadAsStringAsync(cancellationToken);
         return json;
     }

     [McpServerTool, Description("Create a new item via the API.")]
